#!/usr/bin/env python3
"""
CCG Feasibility Wizard — Themed UI rebuild
Run from your REPO ROOT:
    python3 setup-feasibility-themed.py
"""

import os

BASE = "frontend/components/feasibility-test"
files = {}

# ui/InfoDrawer.tsx
files[f"{BASE}/ui/InfoDrawer.tsx"] = "import { useState } from 'react'\nimport type { QuestionItem } from '../data/questions'\n\nexport default function InfoDrawer({ item }: { item: QuestionItem }) {\n  const [open, setOpen] = useState(false)\n  if (!item.info) return null\n\n  return (\n    <div style={{ flexShrink: 0 }}>\n      <button\n        type=\"button\"\n        onClick={e => { e.stopPropagation(); setOpen(!open) }}\n        aria-expanded={open}\n        aria-label={`More info about ${item.label}`}\n        style={{\n          width: 20, height: 20,\n          border: `1px solid ${open ? 'var(--accent)' : 'var(--border)'}`,\n          background: open ? 'var(--accent)' : 'transparent',\n          color: open ? 'var(--bg)' : 'var(--text-muted)',\n          fontSize: 11, fontWeight: 700,\n          fontFamily: 'var(--font-ui)',\n          cursor: 'pointer',\n          display: 'flex', alignItems: 'center', justifyContent: 'center',\n          transition: 'all 200ms ease',\n          flexShrink: 0,\n          borderRadius: 0,\n        }}\n      >\n        i\n      </button>\n\n      {open && (\n        <div style={{\n          marginTop: 10,\n          background: 'var(--bg-deep)',\n          border: '1px solid var(--border)',\n          padding: '14px 16px',\n          display: 'flex', flexDirection: 'column', gap: 12,\n        }}>\n          {item.info.whatItMeans && (\n            <div>\n              <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 5 }}>What it means</p>\n              <p style={{ fontFamily: 'var(--font-body)', fontSize: 13, color: 'var(--text-muted)', lineHeight: 1.7, margin: 0 }}>{item.info.whatItMeans}</p>\n            </div>\n          )}\n          {item.info.howToAssess && (\n            <div>\n              <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 5 }}>How to assess it</p>\n              <p style={{ fontFamily: 'var(--font-body)', fontSize: 13, color: 'var(--text-muted)', lineHeight: 1.7, margin: 0 }}>{item.info.howToAssess}</p>\n            </div>\n          )}\n          {item.info.whyWeAsk && (\n            <div>\n              <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 5 }}>Why we ask</p>\n              <p style={{ fontFamily: 'var(--font-body)', fontSize: 13, color: 'var(--text-muted)', lineHeight: 1.7, margin: 0 }}>{item.info.whyWeAsk}</p>\n            </div>\n          )}\n        </div>\n      )}\n    </div>\n  )\n}\n"

# ui/CheckItem.tsx
files[f"{BASE}/ui/CheckItem.tsx"] = "import type { QuestionItem } from '../data/questions'\nimport InfoDrawer from './InfoDrawer'\n\ninterface CheckItemProps {\n  item:     QuestionItem\n  checked:  boolean\n  onChange: (id: string, checked: boolean) => void\n}\n\nexport default function CheckItem({ item, checked, onChange }: CheckItemProps) {\n  return (\n    <div\n      onClick={() => onChange(item.id, !checked)}\n      style={{\n        display: 'flex',\n        alignItems: 'flex-start',\n        gap: 12,\n        padding: checked ? '14px 16px' : '11px 14px',\n        background: checked ? 'var(--bg-deep)' : 'var(--bg-card)',\n        border: `1px solid ${checked ? 'var(--accent)' : 'var(--border)'}`,\n        cursor: 'pointer',\n        transition: 'all 200ms ease',\n        marginBottom: 6,\n        boxShadow: checked ? '0 0 18px rgba(255,211,105,0.07)' : 'none',\n      }}\n    >\n      <div style={{\n        flexShrink: 0,\n        marginTop: 2,\n        width: checked ? 20 : 16,\n        height: checked ? 20 : 16,\n        border: `${checked ? 2 : 1}px solid ${checked ? 'var(--accent)' : 'var(--border)'}`,\n        background: checked ? 'var(--accent)' : 'transparent',\n        display: 'flex', alignItems: 'center', justifyContent: 'center',\n        transition: 'all 200ms ease',\n      }}>\n        {checked && (\n          <svg width=\"10\" height=\"10\" viewBox=\"0 0 10 10\" fill=\"none\">\n            <path d=\"M1.5 5L3.8 7.5L8.5 2\" stroke=\"var(--bg)\" strokeWidth=\"1.8\" strokeLinecap=\"round\" strokeLinejoin=\"round\"/>\n          </svg>\n        )}\n      </div>\n\n      <div style={{ flex: 1, display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 8, minWidth: 0 }}>\n        <span style={{\n          fontFamily: 'var(--font-ui)',\n          fontSize: checked ? 13 : 12,\n          fontWeight: checked ? 600 : 400,\n          letterSpacing: '0.1em',\n          textTransform: 'uppercase',\n          color: checked ? 'var(--text)' : 'var(--text-muted)',\n          transition: 'all 200ms ease',\n          lineHeight: 1.5,\n        }}>\n          {item.label}\n        </span>\n        {item.info && <InfoDrawer item={item} />}\n      </div>\n    </div>\n  )\n}\n"

# ui/CorrectableRow.tsx
files[f"{BASE}/ui/CorrectableRow.tsx"] = "import type { CorrectableOption } from '../data/questions'\nimport { correctableOptions } from '../data/questions'\n\ninterface CorrectableRowProps {\n  label:     string\n  required?: boolean\n  selected:  CorrectableOption | null\n  onChange:  (value: CorrectableOption) => void\n}\n\nexport default function CorrectableRow({ label, required, selected, onChange }: CorrectableRowProps) {\n  return (\n    <div style={{\n      marginBottom: 24,\n      paddingBottom: 24,\n      borderBottom: '1px solid var(--border)',\n    }}>\n      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}>\n        <span style={{\n          fontFamily: 'var(--font-ui)',\n          fontSize: 10,\n          fontWeight: 600,\n          letterSpacing: '0.2em',\n          textTransform: 'uppercase',\n          color: 'var(--text-muted)',\n        }}>\n          {label}\n        </span>\n        {required && (\n          <span style={{\n            fontFamily: 'var(--font-ui)',\n            fontSize: 8,\n            letterSpacing: '0.15em',\n            textTransform: 'uppercase',\n            color: 'var(--accent)',\n            border: '1px solid var(--accent)',\n            padding: '2px 6px',\n          }}>\n            Required\n          </span>\n        )}\n      </div>\n\n      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>\n        {correctableOptions.map(opt => {\n          const isSelected = selected === opt.value\n          return (\n            <button\n              key={opt.value}\n              type=\"button\"\n              onClick={() => onChange(opt.value)}\n              style={{\n                fontFamily: 'var(--font-ui)',\n                fontSize: isSelected ? 11 : 10,\n                fontWeight: isSelected ? 700 : 400,\n                letterSpacing: '0.15em',\n                textTransform: 'uppercase',\n                padding: isSelected ? '10px 22px' : '8px 16px',\n                background: isSelected ? 'var(--accent)' : 'var(--bg-card)',\n                color: isSelected ? 'var(--bg)' : 'var(--text-muted)',\n                border: `1px solid ${isSelected ? 'var(--accent)' : 'var(--border)'}`,\n                cursor: 'pointer',\n                transition: 'all 200ms ease',\n                boxShadow: isSelected ? '0 0 20px rgba(255,211,105,0.12)' : 'none',\n                borderRadius: 0,\n              }}\n            >\n              {opt.label}\n            </button>\n          )\n        })}\n      </div>\n    </div>\n  )\n}\n"

# ui/EstimateDisplay.tsx
files[f"{BASE}/ui/EstimateDisplay.tsx"] = "import { calculateEstimate } from '../logic/estimate'\nimport type { EstimateInput } from '../logic/estimate'\n\nexport default function EstimateDisplay({ input }: { input: EstimateInput }) {\n  const result = calculateEstimate(input)\n\n  return (\n    <div style={{\n      background: 'var(--bg-deep)',\n      border: '1px solid var(--border)',\n      padding: '20px 24px',\n    }}>\n      <p style={{\n        fontFamily: 'var(--font-ui)',\n        fontSize: 9,\n        letterSpacing: '0.25em',\n        textTransform: 'uppercase',\n        color: 'var(--text-muted)',\n        marginBottom: 10,\n        margin: '0 0 10px',\n      }}>\n        Estimate\n      </p>\n\n      {result.available && result.range ? (\n        <div>\n          <p style={{\n            fontFamily: 'var(--font-display)',\n            fontSize: 32,\n            fontWeight: 400,\n            color: 'var(--text)',\n            margin: '0 0 4px',\n          }}>\n            ${result.range.low.toLocaleString()} \u2013 ${result.range.high.toLocaleString()}\n          </p>\n          <p style={{ fontFamily: 'var(--font-body)', fontSize: 13, color: 'var(--text-muted)', margin: 0 }}>\n            {result.label}\n          </p>\n        </div>\n      ) : (\n        <p style={{\n          fontFamily: 'var(--font-ui)',\n          fontSize: 12,\n          fontWeight: 500,\n          letterSpacing: '0.05em',\n          color: 'var(--text)',\n          margin: '0 0 8px',\n        }}>\n          {result.label}\n        </p>\n      )}\n\n      <p style={{\n        fontFamily: 'var(--font-body)',\n        fontSize: 12,\n        color: 'var(--text-muted)',\n        lineHeight: 1.7,\n        margin: '10px 0 0',\n      }}>\n        {result.note}\n      </p>\n    </div>\n  )\n}\n"

# ui/ResultsDisplay.tsx
files[f"{BASE}/ui/ResultsDisplay.tsx"] = "import type { ScoreBreakdown } from '../logic/calculator'\nimport EstimateDisplay from './EstimateDisplay'\n\ninterface ResultsDisplayProps {\n  results:        ScoreBreakdown\n  weightCt:       number\n  onStartOver:    () => void\n  onRequestQuote: () => void\n}\n\nconst bandColor: Record<string, string> = {\n  '80-100': '#86efac',\n  '60-79':  '#7dd3fc',\n  '40-59':  '#fcd34d',\n  '18-39':  '#fb923c',\n  '0-17':   '#f87171',\n}\n\nexport default function ResultsDisplay({ results, weightCt, onStartOver, onRequestQuote }: ResultsDisplayProps) {\n  const pct   = Math.max(0, Math.min(100, results.feasibilityPercent))\n  const color = bandColor[results.band]\n\n  return (\n    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>\n\n      {/* Score hero */}\n      <div style={{\n        background: 'var(--bg-card)',\n        border: '1px solid var(--border)',\n        padding: '28px 24px',\n        textAlign: 'center',\n      }}>\n        <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.25em', textTransform: 'uppercase', color: 'var(--text-muted)', margin: '0 0 12px' }}>\n          Feasibility Score\n        </p>\n        <p style={{ fontFamily: 'var(--font-display)', fontSize: 72, fontWeight: 400, color, lineHeight: 1, margin: '0 0 12px' }}>\n          {pct}%\n        </p>\n        <p style={{ fontFamily: 'var(--font-ui)', fontSize: 11, fontWeight: 600, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--text-muted)', margin: 0 }}>\n          {results.recommendation}\n        </p>\n      </div>\n\n      {/* Progress bar */}\n      <div style={{ height: 2, background: 'var(--border)', overflow: 'hidden' }}>\n        <div style={{\n          height: '100%',\n          width: `${pct}%`,\n          background: color,\n          transition: 'width 800ms cubic-bezier(0.16,1,0.3,1)',\n        }} />\n      </div>\n\n      {/* Score breakdown */}\n      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>\n        {[\n          { label: 'Positive',    value: results.positiveScore    },\n          { label: 'Limiting',    value: results.limitingScore    },\n          { label: 'Structural',  value: results.structuralScore  },\n          { label: 'Correctable', value: results.correctableScore },\n        ].map(row => (\n          <div key={row.label} style={{\n            background: 'var(--bg-card)',\n            border: '1px solid var(--border)',\n            padding: '14px 16px',\n          }}>\n            <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--text-muted)', margin: '0 0 6px' }}>\n              {row.label}\n            </p>\n            <p style={{\n              fontFamily: 'var(--font-display)',\n              fontSize: 26,\n              fontWeight: 400,\n              color: row.value >= 0 ? 'var(--text)' : '#f87171',\n              margin: 0,\n            }}>\n              {row.value >= 0 ? '+' : ''}{row.value}\n            </p>\n          </div>\n        ))}\n      </div>\n\n      {/* Net / Max */}\n      <div style={{\n        display: 'flex',\n        justifyContent: 'space-between',\n        borderTop: '1px solid var(--border)',\n        paddingTop: 16,\n      }}>\n        <span style={{ fontFamily: 'var(--font-ui)', fontSize: 10, letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--text-muted)' }}>\n          Net Score &nbsp;<strong style={{ color: 'var(--text)' }}>{results.netScore}</strong>\n        </span>\n        <span style={{ fontFamily: 'var(--font-ui)', fontSize: 10, letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--text-muted)' }}>\n          Max &nbsp;<strong style={{ color: 'var(--text)' }}>{results.maxPossible}</strong>\n        </span>\n      </div>\n\n      {/* Recommendation card */}\n      <div style={{\n        background: 'var(--bg-card)',\n        border: `1px solid ${color}`,\n        padding: '20px 24px',\n        boxShadow: `0 0 24px ${color}18`,\n      }}>\n        <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.25em', textTransform: 'uppercase', color: 'var(--text-muted)', margin: '0 0 8px' }}>\n          Recommended Service\n        </p>\n        <p style={{ fontFamily: 'var(--font-display)', fontSize: 28, fontWeight: 400, color: 'var(--text)', margin: '0 0 6px' }}>\n          {results.recommendation}\n        </p>\n        <p style={{ fontFamily: 'var(--font-body)', fontSize: 13, color: 'var(--text-muted)', margin: 0 }}>\n          Estimated material loss: <span style={{ color: 'var(--text)', fontWeight: 500 }}>{results.weightLoss}</span>\n        </p>\n      </div>\n\n      {/* Estimate */}\n      <EstimateDisplay input={{ weightCt, recommendation: results.recommendation, feasibilityPercent: results.feasibilityPercent }} />\n\n      {/* Actions */}\n      <div style={{ display: 'flex', flexDirection: 'column', gap: 10, paddingTop: 8 }}>\n        <button\n          type=\"button\"\n          onClick={onRequestQuote}\n          className=\"btn-primary\"\n          style={{ width: '100%', justifyContent: 'center' }}\n        >\n          Request a Quote\n        </button>\n        <button\n          type=\"button\"\n          onClick={onStartOver}\n          className=\"btn-secondary\"\n          style={{ width: '100%', justifyContent: 'center' }}\n        >\n          Start Over\n        </button>\n      </div>\n\n    </div>\n  )\n}\n"

# FeasibilityWizard.tsx
files[f"{BASE}/FeasibilityWizard.tsx"] = "import { useState, useCallback, Dispatch, SetStateAction } from 'react'\nimport type { CorrectableOption } from './data/questions'\nimport { positiveItems, limitingItems, structuralItems, correctableRows } from './data/questions'\nimport { calculateAll } from './logic/calculator'\nimport type { CorrectableSelections, ScoreBreakdown } from './logic/calculator'\nimport CheckItem from './ui/CheckItem'\nimport CorrectableRowComponent from './ui/CorrectableRow'\nimport ResultsDisplay from './ui/ResultsDisplay'\n\ninterface StoneInfo {\n  species: string; variety: string; weightCt: string; dimensions: string; cut: string\n}\n\ntype WizardStep = 'stone-info' | 'positive' | 'limiting' | 'structural' | 'correctable' | 'results'\nconst STEPS: WizardStep[] = ['stone-info', 'positive', 'limiting', 'structural', 'correctable', 'results']\n\nconst STEP_LABELS: Record<WizardStep, string> = {\n  'stone-info':  'Stone Information',\n  'positive':    'Positive Characteristics',\n  'limiting':    'Limiting Characteristics',\n  'structural':  'Structural Condition',\n  'correctable': 'Correctable Likelihood',\n  'results':     'Results',\n}\n\nconst STEP_INSTRUCTIONS: Record<WizardStep, string> = {\n  'stone-info':  'Fill in what you know. Leave anything blank that you are unsure of.',\n  'positive':    \"Describe your stone's CURRENT state. Circle ALL that apply. Leave the rest unmarked.\",\n  'limiting':    \"Describe your stone's CURRENT state. Circle ALL that apply. Leave the rest unmarked.\",\n  'structural':  \"Describe your stone's CURRENT state. Circle ALL that apply. Leave the rest unmarked.\",\n  'correctable': 'For EACH row, select the ONE option that best describes the situation. Structural is required.',\n  'results':     '',\n}\n\nfunction groupBy<T extends { group: string }>(items: T[]): Record<string, T[]> {\n  return items.reduce((acc, item) => {\n    if (!acc[item.group]) acc[item.group] = []\n    acc[item.group].push(item)\n    return acc\n  }, {} as Record<string, T[]>)\n}\n\nexport default function FeasibilityWizard() {\n  const [stoneInfo, setStoneInfo] = useState<StoneInfo>({ species: '', variety: '', weightCt: '', dimensions: '', cut: '' })\n  const [positiveChecked,       setPositiveChecked]       = useState<Set<string>>(new Set())\n  const [limitingChecked,       setLimitingChecked]       = useState<Set<string>>(new Set())\n  const [structuralChecked,     setStructuralChecked]     = useState<Set<string>>(new Set())\n  const [correctableSelections, setCorrectableSelections] = useState<CorrectableSelections>({ external: null, light: null, geometry: null, structural: null })\n  const [currentStep, setCurrentStep] = useState<WizardStep>('stone-info')\n  const [results,     setResults]     = useState<ScoreBreakdown | null>(null)\n\n  const toggleChecked = useCallback(\n    (setter: Dispatch<SetStateAction<Set<string>>>) =>\n      (id: string, checked: boolean) => {\n        setter((prev: Set<string>) => {\n          const next = new Set(prev)\n          checked ? next.add(id) : next.delete(id)\n          return next\n        })\n      }, []\n  )\n\n  const handleCorrectableChange = (row: keyof CorrectableSelections, value: CorrectableOption) => {\n    setCorrectableSelections(prev => ({ ...prev, [row]: value }))\n  }\n\n  const handleNext = () => {\n    const idx = STEPS.indexOf(currentStep)\n    if (currentStep === 'correctable') {\n      setResults(calculateAll(positiveChecked, limitingChecked, structuralChecked, correctableSelections))\n      setCurrentStep('results')\n    } else if (idx < STEPS.length - 2) {\n      setCurrentStep(STEPS[idx + 1])\n    }\n    window.scrollTo({ top: 0, behavior: 'smooth' })\n  }\n\n  const handleBack = () => {\n    const idx = STEPS.indexOf(currentStep)\n    if (idx > 0) setCurrentStep(STEPS[idx - 1])\n    window.scrollTo({ top: 0, behavior: 'smooth' })\n  }\n\n  const handleStartOver = () => {\n    setStoneInfo({ species: '', variety: '', weightCt: '', dimensions: '', cut: '' })\n    setPositiveChecked(new Set()); setLimitingChecked(new Set()); setStructuralChecked(new Set())\n    setCorrectableSelections({ external: null, light: null, geometry: null, structural: null })\n    setResults(null); setCurrentStep('stone-info')\n    window.scrollTo({ top: 0, behavior: 'smooth' })\n  }\n\n  const handleRequestQuote = () => { alert('Connect to inquiry form here') }\n\n  const canProceed     = currentStep !== 'correctable' || correctableSelections.structural !== null\n  const stepIndex      = STEPS.indexOf(currentStep)\n  const totalSteps     = STEPS.length - 1\n  const progressPct    = currentStep === 'results' ? 100 : (stepIndex / totalSteps) * 100\n  const positiveGroups = groupBy(positiveItems)\n  const limitingGroups = groupBy(limitingItems)\n\n  return (\n    <div style={{\n      minHeight: '100vh',\n      background: 'var(--bg-gradient)',\n      paddingTop: 48,\n      paddingBottom: 80,\n    }}>\n      <div style={{ maxWidth: 560, margin: '0 auto', padding: '0 20px' }}>\n\n        {/* Header */}\n        <div style={{ textAlign: 'center', marginBottom: 40 }}>\n          <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.3em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 10 }}>\n            Cutting Corners Gems\n          </p>\n          <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 36, fontWeight: 400, color: 'var(--text)', margin: '0 0 6px', letterSpacing: '0.04em' }}>\n            Stone Evaluation\n          </h1>\n          <div style={{ width: 40, height: 1, background: 'var(--accent)', margin: '0 auto' }} />\n        </div>\n\n        {/* Progress */}\n        {currentStep !== 'results' && (\n          <div style={{ marginBottom: 32 }}>\n            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>\n              <span style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)' }}>\n                {STEP_LABELS[currentStep]}\n              </span>\n              <span style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.1em', color: 'var(--text-muted)' }}>\n                {stepIndex + 1} / {totalSteps}\n              </span>\n            </div>\n            <div style={{ height: 1, background: 'var(--border)', overflow: 'hidden' }}>\n              <div style={{\n                height: '100%',\n                width: `${progressPct}%`,\n                background: 'var(--accent)',\n                transition: 'width 400ms ease',\n              }} />\n            </div>\n          </div>\n        )}\n\n        {/* Step instruction */}\n        {currentStep !== 'results' && STEP_INSTRUCTIONS[currentStep] && (\n          <p style={{\n            fontFamily: 'var(--font-body)',\n            fontSize: 13,\n            color: 'var(--text-muted)',\n            lineHeight: 1.7,\n            marginBottom: 24,\n            paddingBottom: 24,\n            borderBottom: '1px solid var(--border)',\n          }}>\n            {STEP_INSTRUCTIONS[currentStep]}\n          </p>\n        )}\n\n        {/* \u2500\u2500 Stone Info \u2500\u2500 */}\n        {currentStep === 'stone-info' && (\n          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>\n            {[\n              { key: 'species',    label: 'Species',             placeholder: 'e.g. Corundum'       },\n              { key: 'variety',    label: 'Variety',             placeholder: 'e.g. Blue Sapphire'  },\n              { key: 'weightCt',   label: 'Weight (ct)',         placeholder: 'e.g. 2.4'            },\n              { key: 'dimensions', label: 'Dimensions (mm)',     placeholder: 'e.g. 9 x 7 x 5'     },\n              { key: 'cut',        label: 'Current Cut / Shape', placeholder: 'e.g. Oval Mixed Cut' },\n            ].map(field => (\n              <div key={field.key}>\n                <label style={{ display: 'block', fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 6 }}>\n                  {field.label}\n                </label>\n                <input\n                  type=\"text\"\n                  value={stoneInfo[field.key as keyof StoneInfo]}\n                  onChange={e => setStoneInfo(prev => ({ ...prev, [field.key]: e.target.value }))}\n                  placeholder={field.placeholder}\n                  style={{\n                    width: '100%',\n                    background: 'var(--bg-card)',\n                    border: '1px solid var(--border)',\n                    color: 'var(--text)',\n                    fontFamily: 'var(--font-body)',\n                    fontSize: 14,\n                    padding: '10px 14px',\n                    outline: 'none',\n                    transition: 'border-color 200ms ease',\n                    borderRadius: 0,\n                  }}\n                  onFocus={e => e.target.style.borderColor = 'var(--accent)'}\n                  onBlur={e => e.target.style.borderColor = 'var(--border)'}\n                />\n              </div>\n            ))}\n          </div>\n        )}\n\n        {/* \u2500\u2500 Positive \u2500\u2500 */}\n        {currentStep === 'positive' && (\n          <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>\n            {Object.entries(positiveGroups).map(([group, items]) => (\n              <div key={group}>\n                <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.25em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 10, paddingBottom: 6, borderBottom: '1px solid var(--border)' }}>\n                  {group}\n                </p>\n                {items.map(item => (\n                  <CheckItem key={item.id} item={item} checked={positiveChecked.has(item.id)} onChange={toggleChecked(setPositiveChecked)} />\n                ))}\n              </div>\n            ))}\n          </div>\n        )}\n\n        {/* \u2500\u2500 Limiting \u2500\u2500 */}\n        {currentStep === 'limiting' && (\n          <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>\n            {Object.entries(limitingGroups).map(([group, items]) => (\n              <div key={group}>\n                <p style={{ fontFamily: 'var(--font-ui)', fontSize: 9, letterSpacing: '0.25em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 10, paddingBottom: 6, borderBottom: '1px solid var(--border)' }}>\n                  {group}\n                </p>\n                {items.map(item => (\n                  <CheckItem key={item.id} item={item} checked={limitingChecked.has(item.id)} onChange={toggleChecked(setLimitingChecked)} />\n                ))}\n              </div>\n            ))}\n          </div>\n        )}\n\n        {/* \u2500\u2500 Structural \u2500\u2500 */}\n        {currentStep === 'structural' && (\n          <div>\n            {structuralItems.map(item => (\n              <CheckItem key={item.id} item={item} checked={structuralChecked.has(item.id)} onChange={toggleChecked(setStructuralChecked)} />\n            ))}\n          </div>\n        )}\n\n        {/* \u2500\u2500 Correctable \u2500\u2500 */}\n        {currentStep === 'correctable' && (\n          <div>\n            {correctableRows.map(row => (\n              <CorrectableRowComponent\n                key={row.id}\n                label={row.label}\n                required={row.required}\n                selected={correctableSelections[row.id]}\n                onChange={val => handleCorrectableChange(row.id, val)}\n              />\n            ))}\n            {!canProceed && (\n              <p style={{ fontFamily: 'var(--font-ui)', fontSize: 10, letterSpacing: '0.1em', color: 'var(--accent)', marginTop: 8 }}>\n                Structural selection is required before proceeding.\n              </p>\n            )}\n          </div>\n        )}\n\n        {/* \u2500\u2500 Results \u2500\u2500 */}\n        {currentStep === 'results' && results && (\n          <ResultsDisplay\n            results={results}\n            weightCt={parseFloat(stoneInfo.weightCt) || 0}\n            onStartOver={handleStartOver}\n            onRequestQuote={handleRequestQuote}\n          />\n        )}\n\n        {/* \u2500\u2500 Navigation \u2500\u2500 */}\n        {currentStep !== 'results' && (\n          <div style={{ display: 'flex', gap: 10, marginTop: 40 }}>\n            {stepIndex > 0 && (\n              <button type=\"button\" onClick={handleBack} className=\"btn-secondary\" style={{ flex: 1, justifyContent: 'center' }}>\n                Back\n              </button>\n            )}\n            <button\n              type=\"button\"\n              onClick={handleNext}\n              disabled={!canProceed}\n              className=\"btn-primary\"\n              style={{ flex: 1, justifyContent: 'center', opacity: canProceed ? 1 : 0.4, cursor: canProceed ? 'pointer' : 'not-allowed' }}\n            >\n              {currentStep === 'correctable' ? 'See Results' : 'Next'}\n            </button>\n          </div>\n        )}\n\n      </div>\n    </div>\n  )\n}\n"

for filepath, content in files.items():
    os.makedirs(os.path.dirname(filepath), exist_ok=True)
    with open(filepath, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  ✅  {filepath}")

print("\n🎉  Done.")
